{
  "name": "Medicare Savings Programs (MSP)",
  "eligibility": {
    "age": 65,
    "income_limits": "Rhode Island's Medicare Premium Payment Program (MPP), also known as MSP, has two main tiers with updated limits as of February 2026: Qualified Medicare Beneficiary (QMB) - $1,683/month individual, $2,275/month married couple; Qualified Individual (QI) - $2,255/month individual, $3,050/month married couple. SLMB qualifiers are automatically enrolled in QMB. Must be a U.S. citizen or qualified immigrant (e.g., refugees, asylees, Lawful Permanent Residents meeting residency rules). QDWI available for under 65 working disabled individuals (limits not specified in sources).[1][6]",
    "asset_limits": "Individual: $9,950; Married couple: $14,910 for both QMB and QI (federal limits used). Counts typical countable assets; exemptions not detailed in sources but follow federal MSP rules (e.g., home, car often exempt).[2][6]",
    "other_requirements": ["Must have Medicare Parts A and/or B.", "For QDWI: under age 65, working with disabling impairment, not eligible for regular Medicaid.", "Rhode Island expanded eligibility: SLMB moved to QMB as of Feb 2026."]
  },
  "benefits": {
    "type": "financial",
    "value": "QMB: Pays Medicare Part A premiums (if applicable), Part B premiums, co-payments, coinsurance, and deductibles. QI: Pays Medicare Part B premiums only (limited funds, first-come first-served). Automatic enrollment in Extra Help for prescription drugs if qualified. Part B premium ~$185/month in 2025 (state pays).[6][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Contact Rhode Island EOHHS (specific number not in results; call 401-462-0311 or local office per general RI Medicaid process).", "Online: eohhs.ri.gov (MPP section).", "Mail/In-person: Local Medicaid offices or download forms from site.", "Multiple routes via RI Medicaid Sherlock system."],
    "processing_time": "Not specified in sources.",
    "waitlist": "QI has limited funds; first-come, first-served basis.",
    "forms": ["Medicaid Premium Payment Program application (via EOHHS site or Sherlock/Ticket to Work for QDWI)."],
    "documents": ["Proof of Medicare enrollment.", "Income proof (e.g., pay stubs, SSI award).", "Asset statements.", "ID/proof of citizenship or immigration status.", "Social Security statements."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None",
    "regional_variations": null,
    "offices_or_providers": ["Statewide via EOHHS; local offices for in-person."]
  },
  "official_source": "https://eohhs.ri.gov/Consumer/ProgramsServices/MedicarePremiumPaymentProgram.aspx",
  "gotchas": ["QI funds limited - apply early.", "SLMB auto-converts to QMB (expanded as of Feb 2026).", "Must be Medicare enrollee; QDWI only for working disabled under 65.", "Immigration status strict (qualified immigrants only).", "Assets use federal limits; some states disregard more but RI follows standard.", "Separate process for LTSS (long-term services)."],
  "data_shape_notes": "Tiered by QMB/QI with RI-specific income expansions; SLMB folded into QMB; QI first-come first-served with fund limits; statewide uniform."
}

{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross household income must be at or below 60% of Rhode Island's State Median Income (SMI). FFY2026 guidelines (mandatory as of October 1, 2024; applicable for 2026 season): For household size 1: $42,252 (12-month), $10,563 (3-month), $3,521 (1-month); size 2: $55,252/$13,813/$4,604; size 3: $68,253/$17,063/$5,687. Full table extends to size 14: $126,756/$31,689/$10,563. Exact limits set each program year; check current chart at local CAP[1][2][3][4][7].",
    "asset_limits": "No asset limit applies[1].",
    "other_requirements": ["Household includes everyone at the address covered by the same utility bill[1]", "No requirement to be on public assistance, have an unpaid bill, or own/rent status[3]", "Must qualify for LIHEAP to access related programs like Weatherization[4]"]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time grant paid directly to utility or fuel company to help with heating bills. Primary grants based on income, family size, fuel type, and minimum delivery requirements. Amount not fixed per household; varies by factors above. Crisis component for emergencies (e.g., shutoff, broken heater). No cooling assistance[1][4][6][7].",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online via local Community Action Program (CAP) agency portals (e.g., cappri.org, westbaycap.org, ebcap.org); verify email within 30 minutes[3][5][8]", "Phone: Local CAP (e.g., CAPP 401-273-2000, EBCAP 401-437-1000 ext. 6606)[5][8]", "In-person or dropbox at local CAP intake sites; new applicants preferred in-person, arrangements for elderly/disabled[3][5]", "Mail: Send application/documents to local CAP; renewal forms mailed to prior recipients[3][5][7]"],
    "processing_time": "3-5 business days for initial review after document submission; staff contacts for more info[5].",
    "waitlist": "Funding limited; agencies may stop accepting if funds exhausted. Priority for termination notices, shutoffs, prior recipients[5][6].",
    "forms": ["Renewal Application (mailed to prior recipients)", "No Income Form", "Other Income Form", "Rental Income Form", "Support Letter", "Landlord Information Form", "First Appeal Request Form (for denials)[3][7]"],
    "documents": ["Primary applicant: Social Security Card, valid photo ID (non-expired government-issued)", "Household members: Proof for all", "Gas/electric bill, oil/propane ticket", "Income proof (e.g., pay stubs for 12/3/1 months)", "Application checklist recommended[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "null",
    "regional_variations": "Administered statewide by DHS via local Community Action Program (CAP) agencies with some procedural differences (e.g., online portals, phone numbers, dropboxes vary by CAP); priority processing may vary; no explicit grant/benefit differences noted[3][5][7][8].",
    "offices_or_providers": ["Local CAP agencies (e.g., CAPPRI, Westbay CAP, EBCAP); find via DHS or local search[3][5][7][8]"]
  },
  "official_source": "https://dhs.ri.gov/programs-and-services/energy-assistance-programs-heating/low-income-home-energy-assistance-program",
  "gotchas": ["Seasonal: Heating Oct-May (2026 opens Oct 1, 2025); funds limited, apply early[1][3][6]", "Household counts all at address on utility bill, differing from SNAP[1]", "New applicants: Apply in-person preferred; online needs active email verified in 30 min[3][5]", "Crisis only for true emergencies; no cooling aid[1]", "Must update address for renewals; appeals within 15 days[3]", "Related programs (Weatherization) require LIHEAP eligibility first[4]"],
  "data_shape_notes": "Income eligibility at 60% SMI with full table by household size up to 14 and multi-period limits (12/3/1 month); grants scale by income, size, fuel; administered via multiple regional CAP agencies with varying contact methods; no asset test"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
