    "processing_time": "Not specified; program responds to complaints and provides access to services on an as-needed basis without formal processing timeline.",
    "waitlist": null,
    "forms": ["Online contact form"],
    "documents": ["No specific documents required; provide details of complaint or concern when contacting."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to individuals in long-term care facilities and specific locations (nursing homes, assisted living, licensed home care, hospice, Bristol Veterans Home, Eleanor Slater Hospital Regan Building, Zambarano Hospital).",
    "regional_variations": null,
    "offices_or_providers": ["Office of the RI State Long Term Care Ombudsman, housed within the Alliance for Better Long Term Care, 422 Post Road, Suite 204, Warwick, RI 02888"]
  },
  "official_source": "https://alliancebltc.org/ombudsman-program/overview/",
  "gotchas": ["Not a direct service provider like healthcare or financial aid; focuses solely on advocacy and complaint resolution, not personal care or funding.", "Requires the individual to be receiving long-term care services in a covered facility or program; does not cover independent living without licensed services.", "Anyone can file a complaint on behalf of the resident, but services target residents of facilities.", "Operates independently but reports suspected abuse to relevant authorities."],
